import React, { useEffect, useState } from 'react';
import axios from 'axios';
import './ProductStockLevel.css';

const ProductStockLevel = () => {
    const [stockLevels, setStockLevels] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    useEffect(() => {
        const fetchStockLevels = async () => {
            try {
                const response = await axios.get('/api/product-stock-level');
                setStockLevels(response.data);
            } catch (err) {
                setError(err.message);
            } finally {
                setLoading(false);
            }
        };

        fetchStockLevels();
    }, []);

    if (loading) return <div>Loading...</div>;
    if (error) return <div>Error: {error}</div>;

    return (
        <div className="product-stock-level-container">
            <h1>Product Stock Levels</h1>
            <table className="stock-table">
                <thead>
                    <tr>
                        <th>Product</th>
                        <th>Stock Level</th>
                    </tr>
                </thead>
                <tbody>
                    {stockLevels.map((item) => (
                        <tr key={item.id}>
                            <td>{item.productName}</td>
                            <td>{item.stockLevel}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default ProductStockLevel;
